import{_ as t,o as i,c as s,ak as n}from"./chunks/framework.wx14ja8O.js";const m=JSON.parse('{"title":"Code de Conduite","description":"","frontmatter":{},"headers":[],"relativePath":"code-of-conduct.md","filePath":"code-of-conduct.md"}'),a={name:"code-of-conduct.md"};function r(o,e,l,u,c,d){return i(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="code-de-conduite" tabindex="-1">Code de Conduite <a class="header-anchor" href="#code-de-conduite" aria-label="Permalink to “Code de Conduite”">​</a></h1><p>Ce document définit les règles et valeurs qui régissent la communauté <strong>The H@ckers 237</strong>. En contribuant ou en utilisant ce projet, vous acceptez de respecter ces principes.</p><h2 id="notre-engagement" tabindex="-1">Notre Engagement <a class="header-anchor" href="#notre-engagement" aria-label="Permalink to “Notre Engagement”">​</a></h2><p>The H@ckers 237 est un projet open source dédié à l&#39;apprentissage de la cybersécurité offensive dans un cadre <strong>éthique, légal et respectueux</strong>. Nous nous engageons à maintenir un environnement sain, inclusif et bienveillant pour tous les participants, quels que soient leur niveau, leur origine ou leur expérience.</p><h2 id="valeurs-du-projet" tabindex="-1">Valeurs du Projet <a class="header-anchor" href="#valeurs-du-projet" aria-label="Permalink to “Valeurs du Projet”">​</a></h2><ul><li><strong>Partage</strong> - La connaissance se construit collectivement</li><li><strong>Ethique</strong> - Toute technique documentée est destinée à des usages légaux et autorisés</li><li><strong>Rigueur</strong> - Les contenus publiés sont vérifiés et sourcés</li><li><strong>Respect</strong> - Chaque contributeur mérite considération et bienveillance</li><li><strong>Transparence</strong> - Les décisions du projet sont ouvertes et documentées</li></ul><h2 id="comportements-attendus" tabindex="-1">Comportements Attendus <a class="header-anchor" href="#comportements-attendus" aria-label="Permalink to “Comportements Attendus”">​</a></h2><ul><li>Utiliser un langage respectueux et professionnel</li><li>Accepter les critiques constructives avec ouverture</li><li>Citer les sources et respecter la propriété intellectuelle</li><li>Tester les commandes avant de les documenter</li><li>Signaler les erreurs ou inexactitudes plutôt que de les ignorer</li><li>Aider les nouveaux contributeurs à s&#39;intégrer</li><li>Documenter uniquement dans un cadre <strong>éthique et légal</strong></li></ul><h2 id="comportements-inacceptables" tabindex="-1">Comportements Inacceptables <a class="header-anchor" href="#comportements-inacceptables" aria-label="Permalink to “Comportements Inacceptables”">​</a></h2><ul><li>Harcèlement, insultes ou attaques personnelles</li><li>Publication de contenu discriminatoire ou offensant</li><li>Partage de données personnelles sans consentement</li><li>Documentation de techniques ciblant des infrastructures réelles sans autorisation</li><li>Publication d&#39;exploits 0-day non divulgués</li><li>Inclusion de credentials réels ou de données sensibles dans les contributions</li><li>Toute forme de plagiat sans attribution</li></ul><h2 id="utilisations-autorisees" tabindex="-1">Utilisations Autorisées <a class="header-anchor" href="#utilisations-autorisees" aria-label="Permalink to “Utilisations Autorisées”">​</a></h2><p>Ce projet est conçu pour :</p><ul><li>L&#39;apprentissage de la cybersécurité offensive</li><li>La préparation aux certifications (OSCP, CPTS, PT1 etc..)</li><li>Les tests d&#39;intrusion dans des environnements <strong>autorisés</strong></li><li>La recherche en sécurité offensive</li><li>Les labs et environnements de test dédiés (GOAD, HackTheBox, TryHackMe, etc..)</li></ul><h2 id="utilisations-interdites" tabindex="-1">Utilisations Interdites <a class="header-anchor" href="#utilisations-interdites" aria-label="Permalink to “Utilisations Interdites”">​</a></h2><p>Ce projet <strong>ne doit pas</strong> être utilisé pour :</p><ul><li>Attaquer des systèmes sans autorisation explicite</li><li>Compromettre des infrastructures réelles</li><li>Voler des données personnelles ou confidentielles</li><li>Toute activité illégale au regard des lois en vigueur</li></ul><hr><div class="danger custom-block"><p class="custom-block-title">Avertissement légal</p><p>L&#39;utilisation de ces informations sur des systèmes sans autorisation explicite est <strong>illégale</strong> dans la plupart des pays et peut entraîner des poursuites pénales. Les auteurs du projet déclinent toute responsabilité en cas d&#39;utilisation malveillante ou illégale du contenu documenté.</p></div><h2 id="signalement" tabindex="-1">Signalement <a class="header-anchor" href="#signalement" aria-label="Permalink to “Signalement”">​</a></h2><p>Si vous êtes témoin d&#39;un comportement contraire à ce code de conduite ou d&#39;un contenu inapproprié :</p><ol><li>Ouvrir une <strong>issue</strong> sur GitHub avec le label <code>code-of-conduct</code></li><li>Contacter directement les mainteneurs via GitHub</li><li>Soumettre un rapport via les <strong>Discussions GitHub</strong></li></ol><p>Tout signalement sera traité avec confidentialité et sérieux.</p><h2 id="consequences" tabindex="-1">Conséquences <a class="header-anchor" href="#consequences" aria-label="Permalink to “Conséquences”">​</a></h2><p>Les violations de ce code de conduite peuvent entraîner :</p><table tabindex="0"><thead><tr><th>Gravité</th><th>Conséquence</th></tr></thead><tbody><tr><td>Mineure</td><td>Avertissement écrit</td></tr><tr><td>Modérée</td><td>Retrait temporaire des droits de contribution</td></tr><tr><td>Grave</td><td>Exclusion permanente du projet</td></tr><tr><td>Critique</td><td>Exclusion définitive si nécessaire</td></tr></tbody></table><h2 id="responsabilites-des-mainteneurs" tabindex="-1">Responsabilités des Mainteneurs <a class="header-anchor" href="#responsabilites-des-mainteneurs" aria-label="Permalink to “Responsabilités des Mainteneurs”">​</a></h2><p>Les mainteneurs du projet sont responsables de :</p><ul><li>Clarifier et appliquer ce code de conduite</li><li>Prendre des mesures correctives appropriées en cas de violation</li><li>Maintenir la confidentialité des signalements</li><li>Faire évoluer ce document en fonction des besoins de la communauté</li></ul><h2 id="portee" tabindex="-1">Portée <a class="header-anchor" href="#portee" aria-label="Permalink to “Portée”">​</a></h2><p>Ce code de conduite s&#39;applique à tous les espaces du projet :</p><ul><li>Dépôt GitHub (issues, pull requests, discussions)</li><li>Documentation et contenu du wiki</li><li>Toute communication liée au projet</li></ul><h2 id="ressources-legales" tabindex="-1">Ressources Légales <a class="header-anchor" href="#ressources-legales" aria-label="Permalink to “Ressources Légales”">​</a></h2><ul><li><a href="https://www.cnil.fr/fr/la-loi-informatique-et-libertes" target="_blank" rel="noreferrer">Loi Informatique et Libertés France</a></li><li><a href="https://www.justice.gov/jm/jm-9-48000-computer-fraud" target="_blank" rel="noreferrer">Computer Fraud and Abuse Act USA</a></li><li><a href="https://www.coe.int/fr/web/cybercrime/the-budapest-convention" target="_blank" rel="noreferrer">Convention de Budapest sur la cybercriminalité</a></li><li><a href="https://www.ssi.gouv.fr/" target="_blank" rel="noreferrer">Cadre légal du pentest en France</a></li></ul><h2 id="attribution" tabindex="-1">Attribution <a class="header-anchor" href="#attribution" aria-label="Permalink to “Attribution”">​</a></h2><p>Ce code de conduite s&#39;inspire du <a href="https://www.contributor-covenant.org/" target="_blank" rel="noreferrer">Contributor Covenant</a>, version 2.1, adapté aux spécificités d&#39;un projet de cybersécurité offensive.</p><div class="page-footer"><p><span><img src="https://img.shields.io/github/last-commit/Hackthus/The-Hackers-237?label=Last%20updated&amp;style=flat-square&amp;color=gray" alt="Last updated"></span></p><p><span><a href="https://github.com/Hackthus/The-Hackers-237/edit/main/docs/code-of-conduct.md" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/%E2%9C%8F%EF%B8%8F%20Edit%20this%20page-GitHub-black?style=flat-square&amp;logo=github" alt="Edit this page on GitHub"></a></span></p></div>',36)])])}const h=t(a,[["render",r]]);export{m as __pageData,h as default};
